package main

import (
	"log"
	"net"

	pbOrder "grpc-server-reflection/gen/order"
	pbPayment "grpc-server-reflection/gen/payment"
	pbUser "grpc-server-reflection/gen/user"

	"google.golang.org/grpc"
	"google.golang.org/grpc/reflection"
)

const (
	port = ":50051"
)

func main() {
	// Project setup steps:
	// 1. Create project directory: mkdir grpc-server-reflection && cd grpc-server-reflection
	// 2. Initialize Go module: go mod init grpc-server-reflection
	// 3. Create proto directory: mkdir proto
	// 4. Create the .proto files (user.proto, order.proto, payment.proto) inside the 'proto' directory with the content provided.
	// 5. Install protoc compiler (if not already installed) and Go plugins:
	//    go install google.golang.org/protobuf/cmd/protoc-gen-go@latest
	//    go install google.golang.org/grpc/cmd/protoc-gen-go-grpc@latest
	// 6. Generate Go code from protos:
	//    protoc --go_out=. --go_opt=paths=source_relative \
	//           --go-grpc_out=. --go-grpc_opt=paths=source_relative \
	//           proto/*.proto
	//    This will create the 'gen' directory with subdirectories 'user', 'order', 'payment' containing the generated .pb.go and _grpc.pb.go files.
	// 7. Create the Go service implementation files (userService.go, orderService.go, paymentService.go) in the project root with the content provided.
	// 8. Create this main.go file in the project root.
	// 9. Tidy Go modules: go mod tidy
	// 10. Run the server: go run .
	//
	// To test with grpcurl:
	// - List services: grpcurl -plaintext localhost:50051 list
	// - List methods for a service: grpcurl -plaintext localhost:50051 list UserService
	// - Invoke a method (e.g., create a user):
	//   grpcurl -plaintext -d '{"name": "Alice", "email": "alice@example.com"}' localhost:50051 UserService/CreateUser
	// - Invoke a method (e.g., get a user, replace user-1 with actual ID from CreateUser):
	//   grpcurl -plaintext -d '{"id": "user-1"}' localhost:50051 UserService/GetUser

	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("failed to listen: %v", err)
	}

	s := grpc.NewServer()

	// Register multiple service handlers
	pbUser.RegisterUserServiceServer(s, &userServiceServer{})
	pbOrder.RegisterOrderServiceServer(s, &orderServiceServer{})
	pbPayment.RegisterPaymentServiceServer(s, &paymentServiceServer{})

	// Register reflection service on gRPC server.
	// This enables clients like grpcurl to discover and interact with the services dynamically.
	reflection.Register(s)
	log.Printf("gRPC server listening on %s with reflection enabled", port)

	if err := s.Serve(lis); err != nil {
		log.Fatalf("failed to serve: %v", err)
	}
}